+    fn session_tensor_mul_backward_records_expected_gradients() {
+        let mut session = FrankenTorchSession::new(ExecutionMode::Strict);
+        let x = session
+            .tensor_variable(vec![2.0, 4.0], vec![2], true)
+            .expect("lhs tensor variable should succeed");
